const orders = $input.all()[0]?.json?.results || [];
const reviews = $input.all()[1]?.json?.results || [];

const totalOrders = orders.length;
const totalRevenue = orders.reduce((sum, o) => sum + parseFloat(o.total_price || 0), 0).toFixed(2);
const avgOrderValue = (totalRevenue / totalOrders).toFixed(2);

const positiveReviews = reviews.filter(r => r.rating >= 4).length;
const avgRating = reviews.length > 0 ? (reviews.reduce((sum, r) => sum + r.rating, 0) / reviews.length).toFixed(1) : 0;

return {
  orders: totalOrders,
  revenue: totalRevenue,
  aov: avgOrderValue,
  reviews: reviews.length,
  positive_reviews: positiveReviews,
  avg_rating: avgRating,
  sentiment: positiveReviews / Math.max(reviews.length, 1) > 0.8 ? 'positive' : 'mixed'
};

const m = $input.json;
const today = new Date().toISOString().split('T')[0];

return {
  blocks: [
    {
      type: 'header',
      text: {
        type: 'plain_text',
        text: '📊 BULLDOCKS DAILY BRIEFING — ' + today
      }
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `🎯 *SALES METRICS (last 24h)*
• New Orders: ${m.orders}
• Revenue: €${m.revenue}
• Avg Order Value: €${m.aov}

⭐ *REVIEWS & FEEDBACK*
• New Reviews: ${m.reviews}
• Avg Rating: ${m.avg_rating}★
• Sentiment: ${m.sentiment}`
      }
    }
  ]
};
